{
  "title": "product-search-flow",
  "description": "Apply for: product-search-flow",
  "skill": "When a customer searches for a product please check and display the Meta catalog first which is linked to the whatsapp account (catalog ID 1546095553716961). Product RESULTS must render as a carousel or interactive UI**, never a plain-text list. Refinement questions, acknowledgments, and post-selection conversation stay as text. Don't skip clarification just to rush to a carousel - but once you have intent, render visually"
}

{
  "name": "shopifycartconnector",
  "description": "Connects to the brand's Shopify store via the Storefront GraphQL API to create a cart for the customer and return a checkout URL they can open to complete the purchase.\n",
  "base_url": "https://dyheez-ji.myshopify.com/api/2026-04",
  "auth_type": "API_KEY", 
  "requires_certificate": false,
  "auth_config": {
    "api_key": {
      "headers": [
        {
          "field_name": "X-Shopify-Storefront-Access-Token",
          "value": "{{storefront_token}}",
          "prefix": ""
        }
      ]
    }
  }
}

{
  "name": "create_cart_multipleitems",
  "description": "Use this tool when the customer wants to buy or add one or more products to their cart. Pass variables.lines as an array with one entry per SKU, each having merchandiseId (the product variant GID) and quantity. Returns a checkout URL - share it so the customer can complete the purchase. If the response has userErrors, tell the customer which item couldn't be added and offer to adjust.",
  "request_definition": {
    "method": "POST",
    "path": "/graphql.json",
    "body": {
      "content_type": "application/json",
      "params": {
        "query": {
          "type": "string",
          "description": "GraphQL cartCreate mutation. Fixed; do not modify.",
          "binding": {
            "kind": "default",
            "value": "mutation CartCreate($lines: [CartLineInput!]!) { cartCreate(input: { lines: $lines }) { cart { id checkoutUrl totalQuantity cost { subtotalAmount { amount currencyCode } } } userErrors { field message } warnings { code message } } }"
          }
        },
        "variables": {
          "type": "object",
          "description": "GraphQL variables for cart creation.",
          "required": [
            "lines"
          ],
          "properties": {
            "lines": "{\"type\": \"array\", \"description\": \"One entry per SKU the customer wants; each has a variant GID and its quantity.\", \"items\": \"{\\\"type\\\": \\\"object\\\", \\\"required\\\": [\\\"merchandiseId\\\"], \\\"properties\\\": {\\\"merchandiseId\\\": \\\"{\\\\\\\"type\\\\\\\": \\\\\\\"string\\\\\\\", \\\\\\\"description\\\\\\\": \\\\\\\"Product variant GID (gid://shopify/ProductVariant/<id>) for this line item.\\\\\\\"}\\\", \\\"quantity\\\": \\\"{\\\\\\\"type\\\\\\\": \\\\\\\"integer\\\\\\\", \\\\\\\"description\\\\\\\": \\\\\\\"Quantity for this SKU. Defaults to 1 if omitted.\\\\\\\"}\\\"}}\"}"
          }
        }
      },
      "required": [
        "query",
        "variables"
      ]
    }
  },
  "user_auth_required": false
}

{
    "input":"{\"variables\":{\"lines\":[{\"merchandiseId\":\"gid://shopify/ProductVariant/49356391514264\",\"quantity\":2},{\"merchandiseId\":\"gid://shopify/ProductVariant/49356375261336\",\"quantity\":1}]}}"
}

